-- TypeId for SQL Server 2025. Requires database compatibility level 170.

-- ===== sql/00-schema/typeid.sql =====
-- Schema hosting all TypeId objects.
IF SCHEMA_ID(N'typeid') IS NULL
    EXEC (N'CREATE SCHEMA typeid');
GO

-- ===== sql/10-internal/10-typeid.RandomSource.sql =====
-- Internal helper.
-- Scalar UDFs cannot call non-deterministic sources such as CRYPT_GEN_RANDOM
-- or SYSUTCDATETIME directly, so we surface them through a view that
-- typeid.NewUuidV7 selects from.
--
--   UnixMs      : current UTC time as milliseconds since the Unix epoch (fits 48 bits).
--   RandomBytes : 10 cryptographically secure random bytes (CSPRNG), enough to fill
--                 the 74 random bits of a UUIDv7 (rand_a 12 bits + rand_b 62 bits).
CREATE OR ALTER VIEW typeid.RandomSource
AS
SELECT
    DATEDIFF_BIG(MILLISECOND, '1970-01-01', SYSUTCDATETIME()) AS UnixMs,
    CRYPT_GEN_RANDOM(10) AS RandomBytes;
GO

-- ===== sql/10-internal/20-typeid.NewUuidV7.sql =====
-- Internal helper: generate a fresh RFC 9562 UUIDv7 as a canonical
-- lowercase hyphenated string (char(36)).
--
-- Layout (128 bits), per RFC 9562 section 5.7:
--   bytes 0-5  : unix_ts_ms   (48-bit big-endian milliseconds since Unix epoch, UTC)
--   byte  6    : version (0111 = 7) in the high nibble, rand_a high bits in the low nibble
--   byte  7    : rand_a low bits
--   byte  8    : variant (10) in the top two bits, rand_b high bits below
--   bytes 9-15 : rand_b
--
-- The value is assembled in binary(16) and formatted directly from the raw
-- bytes. It is deliberately NOT round-tripped through uniqueidentifier, whose
-- mixed-endian storage would reorder the first three groups.
CREATE OR ALTER FUNCTION typeid.NewUuidV7()
RETURNS char(36)
AS
BEGIN
    DECLARE @unixMs bigint;
    DECLARE @rand binary(10);

    SELECT @unixMs = UnixMs, @rand = RandomBytes
    FROM typeid.RandomSource;

    -- Low 48 bits of the millisecond timestamp, big-endian.
    DECLARE @ts binary(6) = SUBSTRING(CONVERT(binary(8), @unixMs), 3, 6);

    -- Force version (7) and variant (10xx) bits, keeping the rest random.
    -- Go through tinyint so the int -> binary(1) narrowing is unambiguous.
    DECLARE @versionByte binary(1) =
        CONVERT(binary(1), CONVERT(tinyint, (CONVERT(int, SUBSTRING(@rand, 1, 1)) & 0x0F) | 0x70));
    DECLARE @variantByte binary(1) =
        CONVERT(binary(1), CONVERT(tinyint, (CONVERT(int, SUBSTRING(@rand, 3, 1)) & 0x3F) | 0x80));

    DECLARE @uuid binary(16) =
          @ts                       -- bytes 0-5
        + @versionByte              -- byte 6
        + SUBSTRING(@rand, 2, 1)    -- byte 7
        + @variantByte              -- byte 8
        + SUBSTRING(@rand, 4, 7);   -- bytes 9-15

    -- Raw hex (32 chars, no 0x prefix), lowercased, with canonical hyphens.
    DECLARE @hex char(32) = LOWER(CONVERT(char(32), @uuid, 2));

    RETURN LEFT(@hex, 8) + '-'
         + SUBSTRING(@hex, 9, 4) + '-'
         + SUBSTRING(@hex, 13, 4) + '-'
         + SUBSTRING(@hex, 17, 4) + '-'
         + SUBSTRING(@hex, 21, 12);
END
GO

-- ===== sql/10-internal/30-typeid.EncodeBase32.sql =====
-- Internal helper: encode a 128-bit UUID (binary(16)) as the 26-character
-- Crockford base32 suffix used by TypeId.
--
-- The 128 bits are left-padded with two zero bits to reach 130 bits, then
-- split into 26 groups of 5 bits, most significant first. Bits are read with
-- GET_BIT, whose offset 0 is the least significant bit, so bit offset N of the
-- binary maps to "virtual" MSB-first position N; the two pad bits sit at virtual
-- positions 128-129 and always read as 0.
CREATE OR ALTER FUNCTION typeid.EncodeBase32(@bytes binary(16))
RETURNS char(26)
AS
BEGIN
    IF @bytes IS NULL
        RETURN NULL;

    DECLARE @alphabet char(32) = '0123456789abcdefghjkmnpqrstvwxyz';
    DECLARE @out varchar(26) = '';

    DECLARE @i int = 0;
    WHILE @i < 26
    BEGIN
        DECLARE @msb int = 129 - 5 * @i;   -- most significant bit of this group
        DECLARE @val int = 0;

        DECLARE @k int = 0;
        WHILE @k < 5
        BEGIN
            DECLARE @pos int = @msb - @k;
            DECLARE @bit int = CASE WHEN @pos <= 127 THEN GET_BIT(@bytes, @pos) ELSE 0 END;
            SET @val = @val * 2 + @bit;
            SET @k += 1;
        END

        SET @out = @out + SUBSTRING(@alphabet, @val + 1, 1);
        SET @i += 1;
    END

    RETURN @out;
END
GO

-- ===== sql/10-internal/40-typeid.DecodeBase32.sql =====
-- Internal helper: decode a 26-character Crockford base32 suffix back to the
-- 128-bit UUID (binary(16)). Inverse of typeid.EncodeBase32.
--
-- Returns NULL when the input is malformed:
--   * any character outside the (lowercase, case-sensitive) Crockford alphabet;
--   * a leading character above '7', which would require more than 128 bits
--     (26 * 5 = 130 bits, so the top two bits must be zero).
CREATE OR ALTER FUNCTION typeid.DecodeBase32(@suffix char(26))
RETURNS binary(16)
AS
BEGIN
    IF @suffix IS NULL OR LEN(@suffix) <> 26
        RETURN NULL;

    DECLARE @alphabet char(32) = '0123456789abcdefghjkmnpqrstvwxyz';
    DECLARE @out binary(16) = 0x00000000000000000000000000000000;

    DECLARE @i int = 0;
    WHILE @i < 26
    BEGIN
        DECLARE @char char(1) = SUBSTRING(@suffix, @i + 1, 1);
        -- BIN2 collation: canonical (lowercase) alphabet only; reject anything else.
        DECLARE @val int = CHARINDEX(@char, @alphabet COLLATE Latin1_General_BIN2) - 1;

        IF @val < 0
            RETURN NULL;                        -- character not in the alphabet
        IF @i = 0 AND @val > 7
            RETURN NULL;                        -- overflows 128 bits

        DECLARE @msb int = 129 - 5 * @i;
        DECLARE @k int = 0;
        WHILE @k < 5
        BEGIN
            DECLARE @pos int = @msb - @k;
            IF @pos <= 127
            BEGIN
                DECLARE @bit int = RIGHT_SHIFT(@val, 4 - @k) & 1;
                SET @out = SET_BIT(@out, @pos, @bit);
            END
            SET @k += 1;
        END

        SET @i += 1;
    END

    RETURN @out;
END
GO

-- ===== sql/20-public/10-typeid.IsValidPrefix.sql =====
-- Returns 1 when @prefix is a valid TypeId prefix, else 0.
--
-- Per the TypeId spec, a prefix is 0-63 characters of lowercase ASCII [a-z]
-- and underscores, and may neither start nor end with an underscore. The empty
-- prefix is valid; NULL is not.
-- @prefix is intentionally wider than 63 so an over-long value is not silently
-- truncated to 63 by the parameter type before the regex length check runs.
CREATE OR ALTER FUNCTION typeid.IsValidPrefix(@prefix varchar(90))
RETURNS bit
AS
BEGIN
    IF @prefix IS NULL
        RETURN 0;
    IF @prefix = ''
        RETURN 1;
    IF REGEXP_LIKE(@prefix, '^[a-z]([a-z_]{0,61}[a-z])?$')
        RETURN 1;
    RETURN 0;
END
GO

-- ===== sql/20-public/20-typeid.IsValidSuffix.sql =====
-- Returns 1 when @suffix is a valid TypeId suffix, else 0.
--
-- A suffix is exactly 26 characters of the lowercase Crockford base32 alphabet
-- (0-9 and a-z excluding i, l, o, u). The leading character must be '0'-'7'
-- because 26 * 5 = 130 bits encode a 128-bit value, so the top two bits are
-- always zero.
-- @suffix is intentionally wider than 26 so an over-long value is not silently
-- truncated to 26 by the parameter type before the length check runs.
CREATE OR ALTER FUNCTION typeid.IsValidSuffix(@suffix varchar(90))
RETURNS bit
AS
BEGIN
    IF @suffix IS NULL
        RETURN 0;
    IF REGEXP_LIKE(@suffix, '^[0-7][0-9a-hjkmnp-tv-z]{25}$')
        RETURN 1;
    RETURN 0;
END
GO

-- ===== sql/20-public/30-typeid.IsValid.sql =====
-- Returns 1 when @typeid is a well-formed TypeId, else 0.
--
-- The prefix and suffix are split on the LAST underscore. A value with no
-- underscore is treated as an empty-prefix TypeId (bare suffix). A leading
-- underscore is invalid: an empty prefix must be written without a separator.
--
-- @typeid is wider than the 90-char maximum of a valid TypeId so an over-long
-- value stays over-long (and is rejected) instead of being silently truncated
-- to a length that could pass validation.
CREATE OR ALTER FUNCTION typeid.IsValid(@typeid varchar(255))
RETURNS bit
AS
BEGIN
    IF @typeid IS NULL
        RETURN 0;

    DECLARE @revPos int = CHARINDEX('_', REVERSE(@typeid));
    DECLARE @prefix varchar(255);
    DECLARE @suffix varchar(255);

    IF @revPos = 0
    BEGIN
        SET @prefix = '';
        SET @suffix = @typeid;
    END
    ELSE
    BEGIN
        DECLARE @lastPos int = LEN(@typeid) - @revPos + 1;   -- index of the last '_'
        SET @prefix = LEFT(@typeid, @lastPos - 1);
        SET @suffix = SUBSTRING(@typeid, @lastPos + 1, LEN(@typeid));
        IF @prefix = ''
            RETURN 0;   -- leading underscore / empty prefix with separator
    END

    IF typeid.IsValidPrefix(@prefix) = 1 AND typeid.IsValidSuffix(@suffix) = 1
        RETURN 1;
    RETURN 0;
END
GO

-- ===== sql/20-public/40-typeid.GetPrefix.sql =====
-- Returns the prefix of a TypeId (the part before the last underscore),
-- or '' when there is no underscore (empty-prefix TypeId). NULL in, NULL out.
CREATE OR ALTER FUNCTION typeid.GetPrefix(@typeid varchar(255))
RETURNS varchar(63)
AS
BEGIN
    IF @typeid IS NULL
        RETURN NULL;

    DECLARE @revPos int = CHARINDEX('_', REVERSE(@typeid));
    IF @revPos = 0
        RETURN '';

    RETURN LEFT(@typeid, LEN(@typeid) - @revPos);
END
GO

-- ===== sql/20-public/50-typeid.Encode.sql =====
-- Builds a TypeId from a prefix and a canonical UUID string.
--
-- Returns NULL when the prefix is invalid (see typeid.IsValidPrefix) or the
-- UUID is not a 32-hex-digit value (with or without hyphens). Scalar functions
-- cannot raise errors, so invalid input yields NULL rather than throwing.
-- An empty prefix produces the bare 26-character suffix, with no separator.
-- @prefix is wider than 63 so an over-long prefix reaches typeid.IsValidPrefix
-- intact (and is rejected) instead of being silently truncated to 63.
CREATE OR ALTER FUNCTION typeid.Encode(@prefix varchar(90), @uuid char(36))
RETURNS varchar(90)
AS
BEGIN
    IF @uuid IS NULL OR typeid.IsValidPrefix(@prefix) = 0
        RETURN NULL;

    DECLARE @hex varchar(32) = REPLACE(@uuid, '-', '');
    IF NOT REGEXP_LIKE(@hex, '^[0-9a-fA-F]{32}$')
        RETURN NULL;

    DECLARE @suffix char(26) = typeid.EncodeBase32(CONVERT(binary(16), @hex, 2));

    IF @prefix = ''
        RETURN @suffix;
    RETURN @prefix + '_' + @suffix;
END
GO

-- ===== sql/20-public/60-typeid.Decode.sql =====
-- Decodes a TypeId to its canonical lowercase hyphenated UUID string.
-- Returns NULL when @typeid is not a well-formed TypeId.
-- @typeid is wider than 90 so an over-long value is rejected by typeid.IsValid
-- rather than truncated to a length that might pass.
CREATE OR ALTER FUNCTION typeid.Decode(@typeid varchar(255))
RETURNS char(36)
AS
BEGIN
    IF typeid.IsValid(@typeid) = 0
        RETURN NULL;

    DECLARE @bytes binary(16) = typeid.DecodeBase32(RIGHT(@typeid, 26));
    IF @bytes IS NULL
        RETURN NULL;

    DECLARE @hex char(32) = LOWER(CONVERT(char(32), @bytes, 2));
    RETURN LEFT(@hex, 8) + '-'
         + SUBSTRING(@hex, 9, 4) + '-'
         + SUBSTRING(@hex, 13, 4) + '-'
         + SUBSTRING(@hex, 17, 4) + '-'
         + SUBSTRING(@hex, 21, 12);
END
GO

-- ===== sql/20-public/70-typeid.GetTimestamp.sql =====
-- Extracts the embedded UUIDv7 timestamp from a TypeId as a UTC datetime2.
-- Returns NULL when @typeid is not well-formed.
--
-- The first 48 bits of the UUID are unix_ts_ms (big-endian milliseconds since
-- the Unix epoch). The value is added to the epoch as whole days plus the
-- remaining milliseconds so that both DATEADD arguments stay within int range
-- across the full 48-bit timestamp span.
-- @typeid is wider than 90 so an over-long value is rejected by typeid.IsValid
-- rather than truncated to a length that might pass.
CREATE OR ALTER FUNCTION typeid.GetTimestamp(@typeid varchar(255))
RETURNS datetime2
AS
BEGIN
    IF typeid.IsValid(@typeid) = 0
        RETURN NULL;

    DECLARE @bytes binary(16) = typeid.DecodeBase32(RIGHT(@typeid, 26));
    IF @bytes IS NULL
        RETURN NULL;

    -- 48-bit big-endian milliseconds, widened to bigint via two leading zero bytes.
    DECLARE @ms bigint = CONVERT(bigint, 0x0000 + SUBSTRING(@bytes, 1, 6));

    DECLARE @epoch datetime2 = '1970-01-01T00:00:00';
    RETURN DATEADD(MILLISECOND, @ms % 86400000, DATEADD(DAY, @ms / 86400000, @epoch));
END
GO

-- ===== sql/20-public/80-typeid.New.sql =====
-- Generates a brand-new TypeId for the given prefix, e.g. typeid.New('user').
--
-- This is the primary entry point and is safe to use as a column DEFAULT:
--   Id varchar(90) NOT NULL DEFAULT typeid.New('user')
--
-- Returns NULL when the prefix is invalid (see typeid.IsValidPrefix). Pair it
-- with a CHECK (typeid.IsValid(Id) = 1) constraint to reject bad values at
-- write time, since scalar functions cannot raise errors themselves.
CREATE OR ALTER FUNCTION typeid.New(@prefix varchar(90))
RETURNS varchar(90)
AS
BEGIN
    RETURN typeid.Encode(@prefix, typeid.NewUuidV7());
END
GO

